(window.webpackJsonp=window.webpackJsonp||[]).push([[323],{592:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string}</span> <span class=\\"hljs-variable\\">s</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">queries</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{boolean[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> canMakePaliQueries = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">s, queries</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> res=[]\\n  <span class=\\"hljs-keyword\\">let</span> cache=<span class=\\"hljs-built_in\\">Array</span>(<span class=\\"hljs-number\\">26</span>).fill(<span class=\\"hljs-number\\">0</span>)\\n  <span class=\\"hljs-keyword\\">let</span> prefixC=[cache]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;=s.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> code=s.charCodeAt(i<span class=\\"hljs-number\\">-1</span>)<span class=\\"hljs-number\\">-97</span>\\n    <span class=\\"hljs-keyword\\">let</span> preC=prefixC[i<span class=\\"hljs-number\\">-1</span>]\\n    <span class=\\"hljs-keyword\\">let</span> curCache=preC.slice()\\n    curCache[code]++\\n    prefixC[i]=curCache\\n    \\n  }\\n  <span class=\\"hljs-built_in\\">console</span>.log(prefixC)\\n  \\n  \\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;queries.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> [<span class=\\"hljs-keyword\\">from</span>,to,k]=queries[i]\\n    <span class=\\"hljs-keyword\\">let</span> str=s.slice(<span class=\\"hljs-keyword\\">from</span>,to+<span class=\\"hljs-number\\">1</span>)\\n    <span class=\\"hljs-keyword\\">let</span> needPair=<span class=\\"hljs-built_in\\">Math</span>.floor(str.length/<span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">let</span> pCache=prefixC[<span class=\\"hljs-keyword\\">from</span>]\\n    <span class=\\"hljs-keyword\\">let</span> aCache=prefixC[to+<span class=\\"hljs-number\\">1</span>]\\n    <span class=\\"hljs-keyword\\">let</span> curCache=<span class=\\"hljs-built_in\\">Array</span>(<span class=\\"hljs-number\\">26</span>).fill(<span class=\\"hljs-number\\">0</span>)\\n    <span class=\\"hljs-keyword\\">let</span> pair=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;<span class=\\"hljs-number\\">26</span>;i++){\\n      curCache[i]=aCache[i]-pCache[i]\\n      pair+=<span class=\\"hljs-built_in\\">Math</span>.floor(curCache[i] /<span class=\\"hljs-number\\">2</span>)\\n    }\\n    <span class=\\"hljs-keyword\\">if</span>(pair+k&gt;=needPair){\\n      res.push(<span class=\\"hljs-literal\\">true</span>)\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      res.push(<span class=\\"hljs-literal\\">false</span>)\\n    }\\n\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n\\n};\\n</code></pre>\\n"],"titleSlug":"can-make-palindrome-from-substring","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u5b57\u7b26\u4e32&nbsp;<code>s</code>\uff0c\u8bf7\u4f60\u5bf9&nbsp;<code>s</code>&nbsp;\u7684\u5b50\u4e32\u8fdb\u884c\u68c0\u6d4b\u3002</p>\\n\\n<p>\u6bcf\u6b21\u68c0\u6d4b\uff0c\u5f85\u68c0\u5b50\u4e32\u90fd\u53ef\u4ee5\u8868\u793a\u4e3a&nbsp;<code>queries[i] = [left, right, k]</code>\u3002\u6211\u4eec\u53ef\u4ee5 <strong>\u91cd\u65b0\u6392\u5217</strong> \u5b50\u4e32&nbsp;<code>s[left], ..., s[right]</code>\uff0c\u5e76\u4ece\u4e2d\u9009\u62e9 <strong>\u6700\u591a</strong> <code>k</code>&nbsp;\u9879\u66ff\u6362\u6210\u4efb\u4f55\u5c0f\u5199\u82f1\u6587\u5b57\u6bcd\u3002&nbsp;</p>\\n\\n<p>\u5982\u679c\u5728\u4e0a\u8ff0\u68c0\u6d4b\u8fc7\u7a0b\u4e2d\uff0c\u5b50\u4e32\u53ef\u4ee5\u53d8\u6210\u56de\u6587\u5f62\u5f0f\u7684\u5b57\u7b26\u4e32\uff0c\u90a3\u4e48\u68c0\u6d4b\u7ed3\u679c\u4e3a&nbsp;<code>true</code>\uff0c\u5426\u5219\u7ed3\u679c\u4e3a&nbsp;<code>false</code>\u3002</p>\\n\\n<p>\u8fd4\u56de\u7b54\u6848\u6570\u7ec4&nbsp;<code>answer[]</code>\uff0c\u5176\u4e2d&nbsp;<code>answer[i]</code>&nbsp;\u662f\u7b2c&nbsp;<code>i</code>&nbsp;\u4e2a\u5f85\u68c0\u5b50\u4e32&nbsp;<code>queries[i]</code>&nbsp;\u7684\u68c0\u6d4b\u7ed3\u679c\u3002</p>\\n\\n<p>\u6ce8\u610f\uff1a\u5728\u66ff\u6362\u65f6\uff0c\u5b50\u4e32\u4e2d\u7684\u6bcf\u4e2a\u5b57\u6bcd\u90fd\u5fc5\u987b\u4f5c\u4e3a <strong>\u72ec\u7acb\u7684</strong> \u9879\u8fdb\u884c\u8ba1\u6570\uff0c\u4e5f\u5c31\u662f\u8bf4\uff0c\u5982\u679c&nbsp;<code>s[left..right] = &quot;aaa&quot;</code>&nbsp;\u4e14&nbsp;<code>k = 2</code>\uff0c\u6211\u4eec\u53ea\u80fd\u66ff\u6362\u5176\u4e2d\u7684\u4e24\u4e2a\u5b57\u6bcd\u3002\uff08\u53e6\u5916\uff0c\u4efb\u4f55\u68c0\u6d4b\u90fd\u4e0d\u4f1a\u4fee\u6539\u539f\u59cb\u5b57\u7b26\u4e32 <code>s</code>\uff0c\u53ef\u4ee5\u8ba4\u4e3a\u6bcf\u6b21\u68c0\u6d4b\u90fd\u662f\u72ec\u7acb\u7684\uff09</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>s = &quot;abcda&quot;, queries = [[3,3,0],[1,2,0],[0,3,1],[0,3,2],[0,4,1]]\\n<strong>\u8f93\u51fa\uff1a</strong>[true,false,false,true,true]\\n<strong>\u89e3\u91ca\uff1a</strong>\\nqueries[0] : \u5b50\u4e32 = &quot;d&quot;\uff0c\u56de\u6587\u3002\\nqueries[1] :&nbsp;\u5b50\u4e32 = &quot;bc&quot;\uff0c\u4e0d\u662f\u56de\u6587\u3002\\nqueries[2] :&nbsp;\u5b50\u4e32 = &quot;abcd&quot;\uff0c\u53ea\u66ff\u6362 1 \u4e2a\u5b57\u7b26\u662f\u53d8\u4e0d\u6210\u56de\u6587\u4e32\u7684\u3002\\nqueries[3] :&nbsp;\u5b50\u4e32 = &quot;abcd&quot;\uff0c\u53ef\u4ee5\u53d8\u6210\u56de\u6587\u7684 &quot;abba&quot;\u3002 \u4e5f\u53ef\u4ee5\u53d8\u6210 &quot;baab&quot;\uff0c\u5148\u91cd\u65b0\u6392\u5e8f\u53d8\u6210 &quot;bacd&quot;\uff0c\u7136\u540e\u628a &quot;cd&quot; \u66ff\u6362\u4e3a &quot;ab&quot;\u3002\\nqueries[4] :&nbsp;\u5b50\u4e32 = &quot;abcda&quot;\uff0c\u53ef\u4ee5\u53d8\u6210\u56de\u6587\u7684 &quot;abcba&quot;\u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= s.length,&nbsp;queries.length&nbsp;&lt;= 10^5</code></li>\\n\\t<li><code>0 &lt;= queries[i][0] &lt;= queries[i][1] &lt;&nbsp;s.length</code></li>\\n\\t<li><code>0 &lt;= queries[i][2] &lt;= s.length</code></li>\\n\\t<li><code>s</code> \u4e2d\u53ea\u6709\u5c0f\u5199\u82f1\u6587\u5b57\u6bcd</li>\\n</ul>\\n","title":"1177. \u6784\u5efa\u56de\u6587\u4e32\u68c0\u6d4b","relatedTags":["\u6570\u7ec4","\u5b57\u7b26\u4e32"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1177"}')}}]);